430	        const preFreeSlots: number[] = [];      // 更新前就空著的 item，供進場立即使用
431	        const vacatingSlots: number[] = [];     // 本輪退場騰出的 item，Out 完才可用
432	        const outPromises: Promise<void>[] = [];
433	        const deferredEnter: IBountyData[] = [];
